@startuml
package "com" {
    package "iluwatar" {
        package "multiton" {
            class App {
                - LOGGER : Logger
                + App()
                + main(args : String[])
            }
            class Nazgul {
                - name : NazgulName
                - nazguls : Map<NazgulName, Nazgul>
                - Nazgul(name : NazgulName)
                + getInstance(name : NazgulName) : Nazgul
                + getName() : NazgulName
            }
            class NazgulName {
                <<enumeration>>
                ADUNAPHEL
                AKHORAHIL
                DWAR
                HOARMURATH
                JI_INDUR
                KHAMUL
                MURAZOR
                REN
                UVATHA
                + valueOf(name : String) : NazgulName
                + values() : NazgulName[]
            }
            Nazgul --> NazgulName : -name
        }
    }
}
@enduml
